import {{ Injectable }} from '@nestjs/common';
import {{ RatingService }} from './models/rating.model';
import {{ RatingServiceRepository }} from './repositories/rating.repository';

@Injectable()
export class RatingServiceService {{
  constructor(
    private readonly repository: RatingServiceRepository,
  ) {{}}

  async findAll(): Promise<RatingService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<RatingService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<RatingService>): Promise<RatingService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<RatingService>): Promise<RatingService> {{
    return this.repository.update(id, data);
  }}
}}

